class Solution:
    def minRemoveToMakeValid(self, s: str) -> str:
        stack = []
        to_remove_indices = set()

        for i, char in enumerate(s):
            if char == '(':
                stack.append(i)
            elif char == ')':
                if stack:
                    stack.pop()
                else:
                    to_remove_indices.add(i)

        while stack:
            to_remove_indices.add(stack.pop())

        result = []
        for i, char in enumerate(s):
            if i not in to_remove_indices:
                result.append(char)

        return "".join(result)
